sql:
SELECT COUNT(*) 
FROM queries 
WHERE status = 'completed';

SELECT value
FROM settings
WHERE parameter_name = 'default_query_timeout';

SELECT AVG(execution_time) AS average_execution_time
FROM query_logs
WHERE status = 'success';

SELECT AVG(size) AS average_size
FROM collections
WHERE created_at >= date('now', '-30 days');

SELECT collection_name, AVG(size) AS average_size
FROM collections
GROUP BY collection_name;

SELECT COUNT(query_id) AS total_queries, AVG(execution_time) AS average_execution_time
FROM query_logs
WHERE status = 'success';

SELECT collection_name
FROM collections
WHERE collection_id = 1;

SELECT user_id, COUNT(query_id) AS query_count
FROM queries
GROUP BY user_id;

SELECT collection_name, size
FROM collections
ORDER BY size DESC;
